package entitlementbillinghook

import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/entitlement"
	"github.com/openmeterio/openmeter/openmeter/subscription"
	"github.com/openmeterio/openmeter/pkg/models"
)

type (
	EntitlementBillingHook     = models.ServiceHook[entitlement.Entitlement]
	NoopEntitlementBillingHook = models.NoopServiceHook[entitlement.Entitlement]
)

type hook struct{ NoopEntitlementBillingHook }

var _ models.ServiceHook[entitlement.Entitlement] = (*hook)(nil)

func NewEntitlementBillingHook(_ EntitlementBillingHookConfig) EntitlementBillingHook {
	return &hook{}
}

func (h *hook) PreDelete(ctx context.Context, ent *entitlement.Entitlement) error {
	if subscription.IsSubscriptionOperation(ctx) {
		return nil
	}
	// domain-specific guard
	return models.NewGenericForbiddenError(fmt.Errorf("entitlement is managed by billing"))
}

